### Correct Handshake Initiation Handler

The following demonstrates the required ordering of security checks in a handshake handler, consistent with the conventions above:

```rust
use subtle::ConstantTimeEq;
use zeroize::ZeroizeOnDrop;

#[derive(ZeroizeOnDrop)]
pub struct ResponderHandshake {
    static_private: [u8; 32],
    chaining_key: [u8; 32],
    hash: [u8; 32],
    psk: Option<[u8; 32]>,
}

impl ResponderHandshake {
    pub fn process_initiation(
        &mut self,
        msg: &InitiationMessage,
        cookie_checker: &CookieChecker,
    ) -> Result<ResponseMessage, HandshakeError> {
        // 1. Verify MAC1 before any DH (fast reject)
        cookie_checker.verify_mac1(msg)?;

        // 2. Perform DH exchange on authenticated input
        let ephemeral_shared = x25519(self.static_private, msg.ephemeral)?;

        // 3. Derive keys via HMAC-BLAKE2s/HKDF
        let (ck, key) = hkdf_2(&self.chaining_key, &ephemeral_shared);
        self.chaining_key = ck;

        // 4. Decrypt and verify timestamp
        let timestamp = chacha20poly1305_decrypt(&key, &msg.encrypted_timestamp)?;
        self.verify_timestamp_freshness(&timestamp)?;

        // 5. Build response
        Ok(self.build_response())
    }

    fn verify_timestamp_freshness(&self, ts: &Tai64N) -> Result<(), HandshakeError> {
        // Uses constant-time comparison internally
        if ts <= &self.last_timestamp {
            return Err(HandshakeError::ReplayedTimestamp);
        }
        Ok(())
    }
}
```

